static int scene_preset = 0;
static const char* preset_items = "مدينة\0صحراء\0مختبر\0محطة فضاء\0";
static const char* preset_label = "مدينة";

if (ImGui::Begin("المشاهد الجاهزة")) {
 if (ImGui::ListBox("المشهد", &scene_preset, preset_items)) {
 preset_label = scene_preset == 0 ? "مدينة" : (scene_preset == 1 ? "صحراء" : (scene_preset == 2 ? "مختبر" : "محطة فضاء"));
 }

 ImGui::Text("المشهد المختار: %s", preset_label);
}
ImGui::End();
